INSERT INTO `kursuses` (`id`, `kod_kursus`, `kod_institusi`, `nama_kursus`, `jenis_kursus`, `mod_pengajian`, `tempoh`, `kuota`, `tarikh_pendaftaran`, `penerangan`, `created_at`, `updated_at`) VALUES
(1, 'P854-009-4:2020S', 'C-21-G', 'PENDIDIKAN AWAL KANAK-KANAK (SINGLE TIER)', 'TAHAP 4 (SINGLE TIER)', 'SEPENUH MASA', '27 BULAN', NULL, NULL, 'Latihan profesional dalam pengurusan tadika/prasekolah dan pengajaran pendidikan awal kanak-kanak.', '2026-04-07 19:13:45', '2026-04-07 19:13:45'),
(2, 'F432-005-2:2019 / F432-005-3:2019', '78000', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2/TAHAP 3', 'SEPENUH MASA', '12 BULAN / 12 BULAN', NULL, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 19:49:11', '2026-04-07 19:49:11'),
(3, 'HT-012-2:2012 / HT-012-3:2012', '71700 ', 'KULINARI', '-', 'SEPENUH MASA', '-', NULL, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 21:51:34', '2026-04-07 21:51:34'),
(4, 'IT-020-3:2013 / IT-020-4:2013', '71700 ', 'OPERASI SISTEM KOMPUTER', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 15 BULAN', NULL, NULL, 'Program Sistem Komputer memberi fokus kepada kemahiran asas komputer dan teknologi maklumat, termasuk pemasangan, penyelenggaraan, pengendalian perkakasan, perisian dan rangkaian. Pelajar belajar troubleshoot masalah komputer, pengurusan data, serta memastikan sistem beroperasi dengan cekap dan selamat. Program ini melahirkan tenaga mahir dalam pengurusan dan sokongan sistem komputer.', '2026-04-07 21:53:36', '2026-04-07 21:53:36'),
(5, 'N821-001-3:2020', '71700 ', 'PENGURUSAN & PENTADBIRAN PEJABAT', '-', 'SEPENUH MASA', '-', NULL, NULL, 'Program Pengurusan Pejabat memberi fokus kepada kemahiran pentadbiran pejabat termasuk pengurusan dokumen, komunikasi, penggunaan perisian pejabat, pengurusan mesyuarat dan penyelenggaraan rekod. Pelajar belajar mengurus operasi pejabat dengan cekap dan profesional. Program ini melahirkan tenaga mahir yang mampu menyokong operasi organisasi dengan teratur dan berkesan.', '2026-04-07 21:54:49', '2026-04-07 21:54:49'),
(6, 'MC-091-2:2013 / MC-091-3:2013 / MC-091-4:2013', 'C-21-G', 'PERKHIDMATAN KEJURUTERAAN AUTOMASI INDUSTRI', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '2 TAHUN 9 BULAN', NULL, NULL, 'Pelajar akan mempelajari pemasangan, pengujian, pengendalian dan penyelenggaraan sistem automasi seperti PLC, sensor, panel kawalan, motor, pneumatik dan hidraulik. Latihan menekankan gabungan teori dan amali, selaras keperluan industri sebenar bagi melahirkan tenaga kerja mahir yang kompeten, berdisiplin dan berdaya saing. Graduan berpeluang bekerja sebagai Juruteknik Automasi, Juruteknik Penyelenggaraan, Automation Engineer Support atau melanjutkan kerjaya ke tahap lebih tinggi dalam bidang automasi industri.', '2026-04-07 22:29:49', '2026-04-07 22:29:49'),
(7, '1561-005-2:2022 / 1561-005-3:2022', '47160', 'KULINARI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 9 BULAN', NULL, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 22:36:14', '2026-04-07 22:36:14'),
(8, 'HT-014-2:2011 / HT-014-3:2011', '47160', 'PEMBUATAN PASTRI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 6 BULAN', 6, NULL, 'Program Pembuatan Pastri memberi fokus kepada kemahiran menyediakan pelbagai pastri, kek dan manisan. Pelajar belajar teknik asas pastri seperti menguli, membakar, menghias, kawalan suhu, penyediaan krim dan doh, serta kebersihan dapur. Program ini melahirkan pembuat pastri yang mahir, kreatif dan mampu menghasilkan produk berkualiti mengikut standard industri.', '2026-04-07 22:38:57', '2026-04-07 22:38:57'),
(9, 'G452-002-2:2018 / G452-002-3:2018', 'L01143', 'AUTOMOTIF', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', 'SEPENUH MASA', 3, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 22:40:45', '2026-04-07 22:40:45'),
(10, 'MC-024-3:2012', 'L01143', 'PROSES KIMPALAN ARKA KEPINGAN LOGAM', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', 4, '2026-05-19', 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-07 22:43:10', '2026-04-07 22:43:10'),
(11, 'S960-002-3:2020S', 'L01143', 'PERKHIDMATAN AUTOMASI INDUSTRI', 'TAHAP 2', 'SEPENUH MASA', '6 BULAN', NULL, NULL, 'Program Automasi memberi fokus kepada penggunaan sistem kawalan, sensor, PLC, robotik dan mesin automatik dalam industri. Pelajar belajar memasang, menguji, menyelenggara dan menambah baik sistem automasi bagi meningkatkan kecekapan pengeluaran. Program ini melahirkan tenaga mahir yang mampu mengendalikan peralatan automasi moden dengan selamat dan profesional.', '2026-04-07 22:44:47', '2026-04-07 22:44:47'),
(12, 'HT-013-3-2011', 'L02138', 'PEMBUATAN ROTI (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '15 BULAN', 15, '2026-05-09', 'Program Pembuatan Roti memberi fokus kepada kemahiran menghasilkan pelbagai jenis roti, bun dan pastri asas. Pelajar belajar menyediakan doh, teknik menguli, proses penapaian, membakar dengan betul serta kawalan kualiti dan kebersihan dapur. Program ini melahirkan pembuat roti yang mahir, cekap dan memenuhi standard industri bakeri.', '2026-04-07 22:53:05', '2026-04-07 22:53:05'),
(13, 'HT-012-3-2012S', 'L02138', 'PENYEDIAAN & PENGELUARAN MAKANAN (SINGGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '12 BULAN', 3, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 22:54:35', '2026-04-07 22:54:35'),
(14, 'F432-005-3-2019', 'L02138', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK (SINGLE TIER)', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 4 BULAN', 4, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 22:56:00', '2026-04-07 22:56:00'),
(15, 'I561-005-3:2022S', 'L02138', 'OPERASI SENI KULINARI', 'SINGLE TIER', 'SEPENUH MASA', '17 BULAN', 8, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 22:57:58', '2026-04-07 22:57:58'),
(16, 'S960-002-3:2020', 'L02138', 'PERKHIDMATAN ESTETIK (SINGLE TI)', 'SINGLE TIER', 'SEPENUH MASA', '17 BULAN', 2, '2026-04-11', 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-07 23:00:48', '2026-04-07 23:00:48'),
(17, 'I561-005-2:2022 / I561-005-3:2022 / HT-012-4:2011', 'L02138', 'PENYEDIAAN & PENGELUARAN MAKANAN', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '8 BULAN / 9 BULAN / 10 BULAN', 4, NULL, 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-07 23:02:22', '2026-04-07 23:02:22'),
(18, 'F432-005-2:2019 / F432-005-3:2019', 'L02138', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '8 BULAN / 9 BULAN', 6, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 23:04:27', '2026-04-07 23:04:27'),
(19, 'MC-024-3:2012', '42000', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, '2026-05-19', 'Program ini memberikan kemahiran lanjutan dalam kimpalan arka logam menggunakan teknik shielded metal arc welding (SMAW). Pelajar akan mempelajari cara menyediakan bahan dan peralatan kimpalan, melaksanakan kimpalan pada pelbagai posisi dan jenis sambungan, mematuhi prosedur keselamatan industri, serta melakukan pemeriksaan dan penilaian kualiti hasil kimpalan.', '2026-04-07 23:18:04', '2026-04-07 23:18:04'),
(20, 'G452-002-2:2018 / G452-002-3:2018 / G452-002-4:2017', '42000', 'AUTOMOTIF', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 12 BULAN / 15 BULAN', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 23:19:33', '2026-04-07 23:19:33'),
(21, 'F432-005-2:2019 / F432-005-3:2019 / F432-005-4:2019', '42000', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 12 BULAN / 18 BULAN', NULL, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-07 23:20:56', '2026-04-07 23:20:56'),
(22, 'S960-002-2:2020 / S960-002-3:2020 / S960-002-4:2020', '42000', 'PERKHIDMATAN KECANTIKAN', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '6 BULAN / 6 BULAN / 12 BULAN', NULL, NULL, 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-07 23:24:14', '2026-04-07 23:24:14'),
(23, 'IT-020-3:2013 / IT-020-4:2013', '42000', 'OPERASI SISTEM KOMPUTER', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '12 BULAN / 21 BULAN', NULL, NULL, 'Program Sistem Komputer memberi fokus kepada kemahiran asas komputer dan teknologi maklumat, termasuk pemasangan, penyelenggaraan, pengendalian perkakasan, perisian dan rangkaian. Pelajar belajar troubleshoot masalah komputer, pengurusan data, serta memastikan sistem beroperasi dengan cekap dan selamat. Program ini melahirkan tenaga mahir dalam pengurusan dan sokongan sistem komputer.', '2026-04-07 23:25:19', '2026-04-07 23:25:19'),
(24, 'F432-005-2:2019 / F432-005-3:2019', 'L02238', 'ELEKTRIK & ELEKTRONIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '2 TAHUN', NULL, NULL, 'Program ini menyediakan kemahiran asas dalam pemasangan, pendawaian dan penyelenggaraan sistem elektrik satu fasa di bangunan kediaman atau komersial kecil. Pelajar akan mempelajari pemasangan litar elektrik mengikut piawaian keselamatan, penyelenggaraan sistem elektrik termasuk pengesanan kerosakan dan pembaikan asas, serta amalan keselamatan kerja semasa bekerja dengan elektrik.', '2026-04-07 23:36:56', '2026-04-07 23:36:56'),
(25, 'ME-011-3:2014', 'L02238', 'OPERASI DAN PENYELENGGARAAN BOILER', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, NULL, 'Program ini memberi latihan kemahiran dalam mengendalikan, memantau dan menyelenggara sistem boiler yang digunakan di industri seperti kilang, loji dan fasiliti komersial. Pelajar akan mempelajari asas operasi boiler, kawalan tekanan dan suhu, langkah keselamatan, prosedur permulaan dan penutupan boiler, pengesanan masalah, serta kerja penyelenggaraan berkala supaya sistem boiler sentiasa beroperasi dengan selamat, cekap dan mengikut piawaian industri.', '2026-04-07 23:38:03', '2026-04-07 23:38:03'),
(26, 'G452-002-2:2018 / G452-002-3:2018', 'L02758', 'AUTOMOTIF', '-', 'SEPENUH MASA', '-', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-07 23:52:01', '2026-04-07 23:52:01'),
(27, 'S960-002-1:2020/S960-002-2:2020', 'L02080', 'KECANTIKAN & PENJAGAAN PERIBADI', 'TAHAP 1 / TAHAP 2', 'SEPENUH MASA', '5 BULAN / 6 BULAN', 3, NULL, 'Program Kecantikan Estetik memberikan latihan dalam penjagaan kulit, rawatan wajah, asas dermatologi, penggunaan peralatan estetik, teknik spa serta penjagaan diri. Pelajar belajar melakukan rawatan kecantikan dengan kaedah yang selamat, profesional dan mengikut standard industri. Program ini melahirkan tenaga mahir dalam perkhidmatan kecantikan dan estetika moden.', '2026-04-08 00:18:15', '2026-04-08 00:18:15'),
(28, 'IT-0583:3:2012', 'L02080', 'REKABENTUK GRAFIK (DIGITAL)', 'TAHAP 2', 'SEPENUH MASA', '12 BULAN', NULL, NULL, 'Program ini memberi pendedahan dan latihan dalam penghasilan reka bentuk visual menggunakan perisian digital. Pelajar akan belajar cara menghasilkan grafik seperti poster, logo, banner, media sosial, bahan promosi dan lain-lain menggunakan prinsip rekabentuk yang betul seperti warna, tipografi, komposisi dan kreativiti. Latihan turut merangkumi penggunaan perisian rekabentuk grafik, pengurusan fail digital serta keperluan asas industri kreatif supaya pelajar mampu menghasilkan hasil kerja yang kemas, menarik dan profesional.', '2026-04-08 00:19:18', '2026-04-08 00:19:18'),
(29, 'MC-024-3:2012', '144465-D', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, '2026-05-19', 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-08 00:29:38', '2026-04-08 00:29:38'),
(30, 'FB-025-3:2012', '144465-D', 'SETIAUSAHA KORPORAT', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', NULL, NULL, 'Program Setiausaha Korporat memberi fokus kepada kemahiran pentadbiran korporat, pengurusan dokumen rasmi, pematuhan undang-undang dan prosedur syarikat, serta komunikasi profesional. Pelajar belajar menyokong operasi organisasi, memastikan pentadbiran syarikat teratur dan mematuhi peraturan. Program ini melahirkan tenaga mahir yang cekap, teratur dan beretika dalam urusan korporat.', '2026-04-08 00:30:56', '2026-04-08 00:30:56'),
(31, 'IT-020-3:2013', '144465-D', 'RANGKAIAN KOMPUTER', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN', NULL, NULL, 'Program Rangkaian Komputer memberi fokus kepada pemasangan, penyelenggaraan dan pengurusan rangkaian komputer. Pelajar belajar konfigurasi router dan switch, keselamatan rangkaian, troubleshooting serta pengurusan trafik data. Program ini melahirkan tenaga mahir yang mampu memastikan rangkaian beroperasi dengan cekap, selamat dan mengikut piawaian industri.', '2026-04-08 00:31:58', '2026-04-08 00:31:58'),
(32, 'F432-005-3:2019S', '144465-D', 'ELEKTRIK', 'TAHAP 3', 'SEPENUH MASA', '1 TAHUN 4 BULAN', 3, '2026-04-11', 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-08 00:33:10', '2026-04-08 00:33:10'),
(33, 'G452-002-2/3:2028', '144465-D', 'AUTOMOTIF', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 3 BULAN', 2, '2026-05-18', 'Kursus automotif ialah kursus yang memberi pendedahan kepada pelajar tentang penyelenggaraan, pemeriksaan dan pembaikan kenderaan. Pelajar akan belajar secara teori dan praktikal berkaitan enjin, sistem brek, transmisi, elektrik kenderaan, suspensi serta penggunaan peralatan bengkel. Kursus ini sesuai untuk mereka yang minat kerja hands-on, suka kenderaan dan ingin membina kemahiran dalam bidang teknikal. Selepas tamat pengajian, pelajar berpeluang bekerja sebagai juruteknik automotif, mekanik, penasihat servis atau menceburi industri berkaitan kenderaan', '2026-04-08 00:34:57', '2026-04-08 00:34:57'),
(34, '1561-005-2/3:2022', '144465-D', 'OPERASI SENI KULINARI', 'SINGLE TIER', 'SEPENUH MASA', '18 BULAN', NULL, '2026-04-11', 'Memberi latihan dalam penyediaan dan pembuatan makanan, termasuk teknik memasak, kebersihan dan keselamatan makanan, kawalan kualiti hidangan serta pengurusan asas operasi dapur. Kursus ini sesuai untuk pelajar yang minat memasak dan ingin bekerja dalam bidang kulinari, katering, restoran atau hotel.', '2026-04-08 00:36:08', '2026-04-08 00:36:08'),
(35, 'G452-007-3:2019S', '144465-D', 'SERVIS KERETA ELEKTRIK & HIBRID (EV)', 'SINGLE TIER', 'SEPENUH MASA', '1 TAHUN 3 BULAN', 6, '2026-05-18', 'Kursus G452-007-3:2019S Servis Kereta Elektrik & Hibrid (EV) ialah latihan kemahiran untuk melahirkan juruteknik yang mampu melakukan pemeriksaan, diagnosis, servis dan pembaikan bagi kenderaan EV dan hibrid mengikut prosedur bengkel serta piawaian keselamatan voltan tinggi. Peserta akan didedahkan kepada kerja selamat sistem HV, penggunaan alat diagnostik seperti scan tool, serta servis komponen utama seperti bateri dan sistem pengecasan, motor elektrik, inverter/convertor, kabel voltan tinggi dan subsistem sokongan kenderaan. Selepas tamat kursus, peserta lebih bersedia untuk bekerja dalam bidang servis EV/Hybrid di pusat servis atau bengkel automotif, termasuk tugasan diagnostik dan penyelenggaraan sistem utama EV.', '2026-04-08 00:37:26', '2026-04-08 00:37:26'),
(36, 'F432-005-2:2019', '53100', 'PEMASANGAN & PENYELENGGARAAN ELEKTRIK', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, '2026-04-11', 'Program Pemasangan & Penyelenggaraan Elektrik direka untuk melatih pelajar dalam kemahiran teknikal pendawaian elektrik domestik dan industri. Melalui latihan amali yang intensif, pelajar akan menguasai teknik pemasangan sistem satu fasa dan tiga fasa, penyelenggaraan perkakas suis, serta pengujian litar mengikut piawaian Suruhanjaya Tenaga. Program ini menyediakan landasan kukuh bagi melahirkan teknisi yang kompeten untuk memenuhi keperluan sektor pembinaan dan fasiliti negara.', '2026-04-08 00:44:27', '2026-04-08 00:44:27'),
(37, '1561-002:2:2018', '53100', 'OPERASI SERVIS MAKANAN', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '1 TAHUN 9 BULAN', NULL, NULL, 'Program Operasi Servis Makanan direka untuk melatih pelajar dalam kemahiran hospitaliti dan pengurusan restoran secara profesional. Melalui latihan amali yang intensif, pelajar akan menguasai teknik penyediaan ruang makan (Mise-en-place), gaya servis makanan (American, French, & Buffet), serta kemahiran layanan pelanggan yang berkualiti tinggi. Program ini memfokuskan kepada standard kebersihan dan keselamatan makanan (HACCP) bagi melahirkan tenaga kerja mahir yang kompeten untuk industri perhotelan dan katering.', '2026-04-08 00:45:34', '2026-04-08 00:45:34'),
(38, 'G452-002-3:2018', 'L02882', 'SERVIS KENDERAAN RINGAN - AUTOMOTIF (SINGLE TIER)', 'TAHAP 3', 'SEPENUH MASA', '21 BULAN', NULL, NULL, 'Kursus ini memberi pengetahuan teori dan latihan praktikal tentang sistem utama kenderaan. Pelajar akan belajar bagaimana kenderaan berfungsi serta cara melakukan servis dan pembaikan dengan menggunakan peralatan bengkel. Latihan biasanya dijalankan di bengkel automotif, makmal latihan, dan latihan industri supaya pelajar mendapat pengalaman sebenar bekerja dengan kenderaan.', '2026-04-08 04:08:10', '2026-04-08 04:08:10'),
(39, 'G452-002-2:2018 / G452-002-3:2018', 'L02882', 'PERKHIDMATAN PEMBAIKAN – KENDERAAAN RINGAN (AUTOMOTIF)', 'SINGLE TIER', 'SEPENUH MASA', '2 TAHUN', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-08 04:09:21', '2026-04-08 04:09:21'),
(40, 'G452-002-2:2018 / G452-002-3:2018', 'L02163', 'AUTOMOTIF', '-', 'SEPENUH MASA', '-', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-08 04:16:18', '2026-04-08 04:16:18'),
(41, 'MC-091-2:2016 / MC-091-3:2016 / MC-091-4:2016', 'L02163', 'AUTOMASI INDUSTRI', 'TAHAP 2 / TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '6 BULAN / 12 BULAN / 15 BULAN', NULL, NULL, 'Program Automasi memberi fokus kepada penggunaan sistem kawalan, sensor, PLC, robotik dan mesin automatik dalam industri. Pelajar belajar memasang, menguji, menyelenggara dan menambah baik sistem automasi bagi meningkatkan kecekapan pengeluaran. Program ini melahirkan tenaga mahir yang mampu mengendalikan peralatan automasi moden dengan selamat dan profesional.', '2026-04-08 04:17:10', '2026-04-08 04:17:10'),
(42, 'T982-001-3:2017 | T982-001-4:2018', '70300', 'PENGURUSAN PENJAGAAN DAN PENDIDIKAN KANAK-KANAK AWAL', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '27 BULAN', NULL, '2026-04-03', 'Program ini memberi fokus kepada kemahiran mengasuh, mendidik dan mengurus perkembangan awal kanak-kanak dari segi kognitif, sosial, emosi dan fizikal. Pelajar belajar perancangan aktiviti pembelajaran, keselamatan dan kesihatan kanak-kanak, komunikasi berkesan serta pengurusan pusat asuhan. Program ini melahirkan pengasuh dan pendidik awal kanak-kanak yang profesional, penyayang dan beretika.', '2026-04-08 04:22:25', '2026-04-08 04:22:25'),
(43, '1561-005-3:2022', '70300', 'OPERASI SENI KULINARI', 'TAHAP 2 / TAHAP 3', 'SEPENUH MASA', '18 BULAN', 0, '2026-04-11', 'Program Kulinari memberi latihan dalam kemahiran penyediaan makanan, teknik masakan, kawalan kebersihan, keselamatan dapur dan pengurusan asas dapur. Pelajar belajar memasak pelbagai hidangan, menyedia bahan, menghias makanan serta mematuhi standard kebersihan makanan. Program ini melahirkan tukang masak yang mahir, kreatif dan profesional untuk industri makanan dan perhotelan.', '2026-04-08 04:23:42', '2026-04-08 04:23:42'),
(44, 'MC-024-3:2012', 'P13A-1', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, NULL, 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-08 04:29:12', '2026-05-06 03:39:00'),
(45, 'G452-002-3:2018-S', 'P13A-1', 'AUTOMOTIF', 'SINGLE TIER', 'SEPENUH MASA', '24 BULAN', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-08 04:30:18', '2026-04-08 04:30:18'),
(46, 'F432-005-3-2019S', 'P13A-1', 'ELEKTRIK', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '16 BULAN', NULL, NULL, 'Program Elektrik memberi fokus kepada kemahiran memasang, menyelenggara dan membaiki sistem pendawaian serta peralatan elektrik. Pelajar akan belajar asas litar elektrik, pendawaian domestik, penggunaan alat pengujian, pematuhan keselamatan dan standard kerja. Program ini melahirkan tenaga mahir yang mampu melakukan kerja pemasangan dan penyelenggaraan elektrik dengan selamat dan betul.', '2026-04-08 04:31:27', '2026-04-08 04:31:27'),
(47, 'MC-024-3:2012', '28600', 'KIMPALAN', 'TAHAP 3', 'SEPENUH MASA', '18 BULAN', NULL, NULL, 'Program Kimpalan melatih pelajar dalam teknik mengimpal struktur logam menggunakan kaedah seperti SMAW, GTAW dan GMAW. Pelajar belajar membaca lukisan teknikal, menyediakan bahan, mengawal mesin kimpal serta mengutamakan keselamatan bengkel. Program ini melahirkan tenaga mahir yang mampu melakukan kerja fabrikasi dan penyambungan logam mengikut standard industri.', '2026-04-08 04:35:33', '2026-04-08 04:35:33'),
(48, 'ET-012-3:2012', '28600', 'PENTADBIRAN PRA SEKOLAH', 'TAHAP 3 / TAHAP 4', 'SEPENUH MASA', '2 TAHUN', NULL, NULL, 'Pentadbiran Pra Sekolah ialah kursus yang memberi pendedahan tentang pengurusan, pentadbiran dan pendidikan awal kanak-kanak di peringkat prasekolah atau tadika. Kursus ini bertujuan melatih pelajar supaya memahami cara mengurus operasi prasekolah serta membimbing perkembangan kanak-kanak secara menyeluruh. Dalam kursus ini, pelajar akan mempelajari asas pendidikan awal kanak-kanak, teknik pengajaran yang sesuai, serta cara mengurus aktiviti pembelajaran yang menyeronokkan dan berkesan untuk kanak-kanak.', '2026-04-08 04:36:43', '2026-04-08 04:40:47'),
(49, 'G452-002-3:2018S', '28600', 'AUTOMOTIF', 'TAHAP 2 / TAHAP 3 (ST)', 'SEPENUH MASA', '2 TAHUN', NULL, NULL, 'Program ini memfokuskan kepada kemahiran asas automotif seperti servis dan baiki kenderaan. Pelajar belajar penyelenggaraan enjin, sistem brek, suspensi, elektrik asas dan keselamatan bengkel. Matlamatnya melahirkan individu yang mahir melakukan kerja servis asas, pemeriksaan dan pembaikan kenderaan ringan.', '2026-04-08 04:37:59', '2026-04-08 04:37:59'),
